class Animal {
  name: string;   // instance property declaration (TypeScript)

  constructor(name: string) {
    this.name = name;
  }

  speak(): string {
    return `${this.name} makes a sound`;
  }
}

const cat = new Animal('Whiskers');
cat.speak();      // "Whiskers makes a sound"
cat.name;         // "Whiskers"
cat instanceof Animal;  // true

// Verbose way
class Point {
  x: number;
  y: number;
  constructor(x: number, y: number) {
    this.x = x;
    this.y = y;
  }
}

// Shorthand with parameter properties — identical runtime result
class Point {
  constructor(
    public x: number,
    public y: number,
  ) {}
}

// Works with all modifiers
class Config {
  constructor(
    public readonly name: string,
    private timeout: number,
    protected retries: number = 3,
  ) {}
}

class BankAccount {
  readonly id: string = crypto.randomUUID();
  public owner: string;
  private #balance: number;   // true private

  constructor(owner: string, initialBalance: number) {
    this.owner = owner;
    this.#balance = initialBalance;
  }

  deposit(amount: number): void {
    if (amount <= 0) throw new RangeError('amount must be positive');
    this.#balance += amount;
  }

  get balance(): number { return this.#balance; }
}

const acc = new BankAccount('Deiva', 1000);
acc.balance;          // 1000
acc.owner = 'Ana';    // OK — public
// acc.#balance = 999; // SyntaxError — JS engine blocks it
// acc.id = 'x';       // TypeScript error — readonly

class Shape {
  constructor(public color: string) {}

  describe(): string {
    return `A ${this.color} shape`;
  }
}

class Circle extends Shape {
  constructor(
    color: string,
    public radius: number,
  ) {
    super(color);   // must call super() before referencing this
  }

  area(): number {
    return Math.PI * this.radius ** 2;
  }

  // Override parent method
  describe(): string {
    return `${super.describe()} (circle, r=${this.radius})`;
  }
}

const c = new Circle('red', 5);
c.describe();       // "A red shape (circle, r=5)"
c.area();           // 78.54
c instanceof Circle;  // true
c instanceof Shape;   // true

abstract class Validator<T> {
  abstract validate(value: T): boolean;
  abstract errorMessage: string;

  // Concrete shared method
  check(value: T): { valid: boolean; error?: string } {
    const valid = this.validate(value);
    return valid ? { valid } : { valid, error: this.errorMessage };
  }
}

class EmailValidator extends Validator<string> {
  errorMessage = 'Invalid email address';

  validate(value: string): boolean {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
  }
}

const ev = new EmailValidator();
ev.check('user@example.com');  // { valid: true }
ev.check('not-an-email');       // { valid: false, error: 'Invalid email address' }

class IdGenerator {
  private static nextId = 1;

  static generate(): number {
    return IdGenerator.nextId++;
  }

  static reset(): void {
    IdGenerator.nextId = 1;
  }
}

IdGenerator.generate();  // 1
IdGenerator.generate();  // 2
IdGenerator.generate();  // 3
IdGenerator.reset();
IdGenerator.generate();  // 1

// Static members are inherited by subclasses
class UserIdGenerator extends IdGenerator {
  static prefix = 'USR';
  static generateUserId() {
    return `${this.prefix}-${this.generate()}`;
  }
}
UserIdGenerator.generateUserId();  // "USR-1"

class Temperature {
  private _celsius: number;

  constructor(celsius: number) {
    this._celsius = celsius;
  }

  get celsius(): number { return this._celsius; }
  set celsius(value: number) {
    if (value < -273.15) throw new RangeError('Below absolute zero');
    this._celsius = value;
  }

  get fahrenheit(): number { return this._celsius * 9/5 + 32; }
  set fahrenheit(value: number) { this.celsius = (value - 32) * 5/9; }
}

const temp = new Temperature(100);
temp.fahrenheit;         // 212
temp.fahrenheit = 32;    // calls setter → celsius = 0
temp.celsius;            // 0

class Stack<T> {
  private items: T[] = [];

  push(item: T): void {
    this.items.push(item);
  }

  pop(): T | undefined {
    return this.items.pop();
  }

  peek(): T | undefined {
    return this.items[this.items.length - 1];
  }

  get size(): number { return this.items.length; }
  get isEmpty(): boolean { return this.items.length === 0; }
}

const numStack = new Stack<number>();
numStack.push(1);
numStack.push(2);
numStack.pop();   // 2

const strStack = new Stack<string>();
strStack.push('a');
