class Widget {
  // (1) class fields are set in declaration order, before the constructor body
  label = 'default';          // public class field
  #count = 0;                 // private class field
  readonly id: string;

  constructor(id: string) {
    // (2) constructor body runs after all field initializers
    this.id = id;
    console.log(this.label); // 'default' — already set
  }
}

// Static class fields — one value shared across all instances
class Config {
  static readonly version = '2.0';
  static instances = 0;

  constructor() { Config.instances++; }
}

console.log(Config.version);   // '2.0'
new Config(); new Config();
console.log(Config.instances); // 2

// A mixin is a function that takes a Base class and extends it
type Constructor<T = {}> = new (...args: any[]) => T;

function Timestamped<TBase extends Constructor>(Base: TBase) {
  return class extends Base {
    createdAt = new Date();
    updatedAt = new Date();

    touch() { this.updatedAt = new Date(); }
  };
}

function Activatable<TBase extends Constructor>(Base: TBase) {
  return class extends Base {
    isActive = false;
    activate()   { this.isActive = true; }
    deactivate() { this.isActive = false; }
  };
}

class User {
  constructor(public name: string) {}
}

// Compose: User + Timestamped + Activatable
const TimestampedActivatableUser = Activatable(Timestamped(User));
const user = new TimestampedActivatableUser('Alice');

user.activate();
user.touch();
console.log(user.isActive, user.updatedAt); // true, <Date>

