import { Injectable, signal } from '@angular/core';

@Injectable({ providedIn: 'root' })
export class CounterService {
  readonly count = signal(0);
  increment() { this.count.update(v => v + 1); }
  reset()     { this.count.set(0); }
}

// counter.service.spec.ts
import { CounterService } from './counter.service';

describe('CounterService', () => {
  let service: CounterService;

  beforeEach(() => {
    service = new CounterService(); // plain instantiation — no TestBed needed
  });

  it('starts at 0', () => expect(service.count()).toBe(0));

  it('increments', () => {
    service.increment();
    expect(service.count()).toBe(1);
  });

  it('resets', () => {
    service.increment(); service.increment();
    service.reset();
    expect(service.count()).toBe(0);
  });
});

import { UserService } from './user.service';
import { HttpClient }  from '@angular/common/http';

describe('UserService', () => {
  let service: UserService;
  let httpMock: jasmine.SpyObj<HttpClient>;

  beforeEach(() => {
    // Create a typed spy — no need for HttpClientTestingModule
    httpMock = jasmine.createSpyObj('HttpClient', ['get']);
    service  = new UserService(httpMock as any);
  });

  it('calls /api/users', () => {
    httpMock.get.and.returnValue(of([]));
    service.getAll().subscribe();
    expect(httpMock.get).toHaveBeenCalledWith('/api/users');
  });
});
